<section class="col-12 panel"><h6>Cabecera</h6><div class="row g-2"><div class="col-md-3"><label>Supervisor</label><select name="supervisor_id" class="form-select"><?php foreach($supervisores as $s): ?><option value="<?= $s['id'] ?>" <?= ($item['supervisor_id']??'')==$s['id']?'selected':'' ?>><?= e($s['nombre'].' '.$s['apellido']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Fecha recepción</label><input type="date" class="form-control" name="fecha_recepcion_cable" value="<?= e($item['fecha_recepcion_cable']??date('Y-m-d')) ?>"></div><div class="col-md-2"><label>Fecha entrega</label><input type="date" class="form-control" name="fecha_entrega_cable" value="<?= e($item['fecha_entrega_cable']??'') ?>"></div><div class="col-md-3"><label>Cable</label><select id="cableSelect" name="cable_id" class="form-select"><?php foreach($cables as $c): ?><option data-json='<?= e(json_encode($c)) ?>' value="<?= $c['id'] ?>" <?= ($item['cable_id']??'')==$c['id']?'selected':'' ?>><?= e($c['numero_cable']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Estado informe</label><select name="estado_informe" class="form-select"><?php foreach(['borrador','finalizado','anulado'] as $e): ?><option <?= ($item['estado_informe']??'')===$e?'selected':'' ?>><?= $e ?></option><?php endforeach; ?></select></div><div class="col-md-4"><label>Origen cable</label><select name="origen_cable" class="form-select"><option value="">Seleccione origen...</option><?php foreach($origenes as $o): ?><option value="<?= e($o['nombre']) ?>" <?= ($item['origen_cable']??'')===$o['nombre']?'selected':'' ?>><?= e($o['nombre']) ?></option><?php endforeach; ?></select></div></div></section>
