<section class="col-md-3 panel"><h6>Reparaciones al ingresar</h6><?php foreach(['rep_ing_mufas_termo'=>'Mufas Termocontraible','rep_ing_mufa_union'=>'Mufa de unión','rep_ing_chaquetas'=>'Chaquetas'] as $n=>$l): ?><label><?= $l ?></label><input type="number" name="<?= $n ?>" class="form-control" value="<?= e($item[$n]??0) ?>"><?php endforeach; ?></section>
