<section class="col-12 panel"><h6>Estado entrega cable</h6><div class="row g-2"><div class="col-md-2"><select name="estado_operativo" class="form-select"><?php foreach(['Operativo','No operativo','En observación','Dado de baja'] as $e): ?><option <?= ($item['estado_operativo']??'')===$e?'selected':'' ?>><?= $e ?></option><?php endforeach; ?></select></div><div class="col-md-2"><input name="destino_cable" class="form-control" placeholder="Destino" value="<?= e($item['destino_cable']??'') ?>"></div><div class="col-md-2"><input name="tipo_enchufe_entrega" class="form-control" placeholder="Tipo enchufe" value="<?= e($item['tipo_enchufe_entrega']??'') ?>"></div><div class="col-md-2"><input name="largo_entrega" class="form-control" placeholder="Largo entrega" value="<?= e($item['largo_entrega']??'') ?>"></div><div class="col-md-2"><input name="marca_entrega" class="form-control" placeholder="Marca" value="<?= e($item['marca_entrega']??'') ?>"></div><div class="col-md-2"><input name="capacidad_aislacion_entrega" class="form-control" placeholder="Capacidad aislación" value="<?= e($item['capacidad_aislacion_entrega']??'') ?>"></div></div></section>
