<section class="col-md-6 panel"><h6>Causa probable</h6><?php foreach($inf->causas as $o): ?><label class="check"><input type="checkbox" name="causas_probables[]" value="<?= e($o) ?>" <?= in_array($o, $selectedValues['causas_probables'], true) ? 'checked' : '' ?>> <?= e($o) ?></label><?php endforeach; ?></section>
<section class="col-12 panel"><h6>Pruebas finales cable</h6><div class="row g-2"><?php foreach(['1min','3min'] as $min): foreach(['Fase N° 1','Fase N° 2','Fase N° 3','Hilo piloto'] as $it): $key=$it.' / '.$min; ?><div class="col-md-3"><label><?= e($key) ?></label><div class="input-group input-group-sm"><input type="hidden" name="pruebas_finales[<?= e($key) ?>][realizada]" value="0"><span class="input-group-text"><input type="checkbox" name="pruebas_finales[<?= e($key) ?>][realizada]" value="1" class="revision-card-realizada" <?= checked_nested($selectedValues, 'pruebas_finales', $key, 'realizada') ?>></span><input class="form-control" name="pruebas_finales[<?= e($key) ?>][valor]" placeholder="Valor" value="<?= value_nested($selectedValues, 'pruebas_finales', $key, 'valor') ?>"><select class="form-select" name="pruebas_finales[<?= e($key) ?>][unidad]"><option <?= (($selectedValues['pruebas_finales'][$key]['unidad']??'')==='Mega Ohm')?'selected':'' ?>>Mega Ohm</option><option <?= (($selectedValues['pruebas_finales'][$key]['unidad']??'')==='Giga Ohm')?'selected':'' ?>>Giga Ohm</option></select></div></div><?php endforeach; endforeach; ?></div></section>
<section class="col-12 panel"><h6>Materiales usados</h6><p class="muted">Seleccione uno o más usuarios y luego los materiales pendientes asociados a sus entregas activas.</p><div id="informeMaterialRows"><?php if(empty($usuariosMateriales)): ?><div class="alert alert-warning py-2">No hay materiales entregados disponibles para uso.</div><?php else: ?><?php $rowsMateriales = !empty($materialesInforme) ? $materialesInforme : [null]; foreach($rowsMateriales as $materialActual): ?><div class="row g-2 mb-2 informe-material-row"><div class="col-md-4"><label>Usuario</label><select class="form-select informe-material-user"><option value="">Seleccione usuario...</option><?php foreach($usuariosConMateriales as $uid=>$nombre): ?><option value="<?= e($uid) ?>" <?= $materialActual && (int)$materialActual['usuario_receptor_id']===(int)$uid?'selected':'' ?>><?= e($nombre) ?></option><?php endforeach; ?></select></div><div class="col-md-5"><label>Material entregado</label><select name="material_detalle_id[]" class="form-select informe-material-select"><option value="">Seleccione material...</option><?php foreach($usuariosMateriales as $mu): ?><option value="<?= e($mu['detalle_id']) ?>" data-user="<?= e($mu['usuario_receptor_id']) ?>" data-disponible="<?= e($mu['cantidad_disponible']) ?>" <?= $materialActual && (int)$materialActual['detalle_id']===(int)$mu['detalle_id']?'selected':'' ?>><?= e($mu['codigo_interno'].' · '.$mu['nombre_material'].' (disp. '.$mu['cantidad_disponible'].' '.$mu['unidad_medida'].')') ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Cantidad usada</label><input type="number" step="0.01" min="0" name="material_cantidad[]" class="form-control informe-material-cantidad" placeholder="0" value="<?= e($materialActual['cantidad_utilizada']??'') ?>"></div><div class="col-md-1 d-flex align-items-end"><button type="button" class="btn btn-outline-light w-100 remove-informe-material">×</button></div></div><?php endforeach; ?><?php endif; ?></div><?php if(!empty($usuariosMateriales)): ?><button type="button" class="btn btn-sm btn-outline-light" id="addInformeMaterial">Agregar material usado</button><?php endif; ?></section>
